    {
      "text": "सफलतापूर्वक संकलित होता है",
      "hint": "संदर्भ वाले स्ट्रक्ट को जीवनकाल एनोटेशन की आवश्यकता होती है"
    },
    {
      "text": "त्रुटि: जीवनकाल निर्दिष्टक गायब है"
    },
    {
      "text": "त्रुटि: जीवनकाल बेमेल",
      "hint": "हमने अभी तक कोई जीवनकाल निर्दिष्ट नहीं किया है"
    },
    {
      "text": "त्रुटि: अमान्य संदर्भ",
      "hint": "संदर्भ मान्य हैं, लेकिन कुछ और गायब है"
    }
  ],
  "questionProse": [
    "क्या यह स्ट्रक्ट परिभाषा संकलित होगी? क्यों या क्यों नहीं?"
  ],
  "explanationProse": [
    "कोड विफल होता है क्योंकि संदर्भ वाले स्ट्रक्ट को जीवनकाल निर्दिष्ट करना होता है। इसे ठीक करने का तरीका यह है:",
    "सामान्य पैटर्न:",
    "सर्वोत्तम अभ्यास:\n      1. जब आपको डेटा को अनिश्चित काल तक संग्रहीत करने की आवश्यकता हो, तो स्वामित्व प्रकार (String) का उपयोग करें\n      2. जब स्ट्रक्ट का जीवनकाल डेटा से स्पष्ट रूप से छोटा हो, तो संदर्भ का उपयोग करें\n      3. जब संदर्भों के अलग-अलग जीवनकाल हो सकते हैं, तो एकाधिक जीवनकाल पैरामीटर पर विचार करें\n      4. जटिल संरचनाओं में जीवनकाल संबंधों का दस्तावेजीकरण करें"
  ]
